import "./style.css"
import React from 'react';
import OwlCarousel from 'react-owl-carousel';
import 'owl.carousel/dist/assets/owl.carousel.css';
import 'owl.carousel/dist/assets/owl.theme.default.css';

function MiniCards  () {

    return <div className={"mini-cards_container"}>
        <OwlCarousel  items={1} className='owl-theme' loop margin={10}
                     responsive={{
                         600: {items:2},
                         768: {items:3},
                         920: {items: 4},
                         1100:{items:5}
                     }}>

        <a href={"https://tena99.github.io/Decor_Color/"} className={"mini-cards_item item"} style={{
            backgroundImage: `url(${process.env.PUBLIC_URL}/images/decor_background.jpg)`,
            backgroundSize: 'cover'}}>
            <img src={process.env.PUBLIC_URL + "/images/decor_logo.svg"} alt={"project_main_page"}/>
            <div className={"mini-cards_item_background"}></div>
        </a>

        <a href={"https://tena99.github.io/elearning/"} className={"mini-cards_item item"} style={{
            backgroundImage: `url(${process.env.PUBLIC_URL}/images/elearning_background.jpg)`,
            backgroundSize: 'cover', backgroundPosition:"center"}}>
            <img src={process.env.PUBLIC_URL + "/images/elearning_logo.svg"} alt={"project_main_page"}/>
            <div className={"mini-cards_item_background"}></div>
        </a>

        <a href={"https://tena99.github.io/Aperture/"} className={"mini-cards_item item"} style={{
            backgroundImage: `url(${process.env.PUBLIC_URL}/images/aperture_background.jpg)`,
            backgroundSize: 'cover',  backgroundPosition:"right"}}>
            <img src={process.env.PUBLIC_URL + "/images/aperture_logo.svg"} alt={"project_main_page"}/>
            <div className={"mini-cards_item_background"}></div>
        </a>

        <a href={"https://tena99.github.io/movie/"} className={"mini-cards_item item"} style={{
            backgroundImage: `url(${process.env.PUBLIC_URL}/images/movie_background.jpg)`,
            backgroundSize: 'cover'}}>
            <img src={process.env.PUBLIC_URL + "/images/movie_logo.svg"} alt={"project_main_page"}/>
            <div className={"mini-cards_item_background"}></div>
        </a>

        <a href={"https://tena99.github.io/Healtcare/"} className={"mini-cards_item item"} style={{
            backgroundImage: `url(${process.env.PUBLIC_URL}/images/healthcare_background.png)`,
            backgroundSize: 'cover',     backgroundColor: "rgba(229,229,229,1)", backgroundPositionX: "-75px"}}>
            <img src={process.env.PUBLIC_URL + "/images/healthcare_logo.svg"} alt={"project_main_page"}/>
            <div className={"mini-cards_item_background"}></div>
        </a>

        </OwlCarousel>
    </div>

}

export default MiniCards